// tsconfig.json üçün qeyd: {"experimentalDecorators": true}

// 1. Sinif Dekoratoru
function sealed(constructor: Function) {
  Object.seal(constructor);
  Object.seal(constructor.prototype);
}
@sealed
class User {
  name: string = "Alice";
  greet() {
    return "Hello, " + this.name;
  }
}
const user = new User();
console.log(user.greet()); // Çıxış: Hello, Alice

// 2. Dekorator Fabriki
function log(prefix: string) {
  return function (constructor: Function) {
    console.log(prefix + " " + constructor.name);
  };
}
@log("Logging")
class Product {
  name: string = "Laptop";
}
// Çıxış: Logging Product

// 3. Metod Dekoratoru
function logMethod(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    console.log("Method " + propertyKey + " called with args: " + args);
    return originalMethod.apply(this, args);
  };
}
class Calculator {
  @logMethod
  add(a: number, b: number): number {
    return a + b;
  }
}
const calc = new Calculator();
console.log(calc.add(5, 3)); // Çıxış: Method add called with args: 5,3
// Çıxış: 8

// 4. Xüsusiyyət Dekoratoru
function readonly(target: any, propertyKey: string) {
  Object.defineProperty(target, propertyKey, { writable: false });
}
class Person {
  @readonly
  name: string = "Bob";
}
const person = new Person();
// person.name = "Charlie"; // Səhv: name yalnız oxuna bilər
console.log(person.name); // Çıxış: Bob

// 5. Parametr Dekoratoru
function logParameter(target: any, propertyKey: string, parameterIndex: number) {
  console.log(`Parameter at index ${parameterIndex} in method ${propertyKey}`);
}
class Example {
  greet(@logParameter message: string) {
    console.log(message);
  }
}
const example = new Example();
example.greet("Hello"); // Çıxış: Parameter at index 0 in method greet
// Çıxış: Hello

// Mağaza sistemi
interface Product {
  id: string;
  name: string;
  price: number;
}

function logAccess(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    console.log(`Accessing ${propertyKey} with args: ${JSON.stringify(args)}`);
    return originalMethod.apply(this, args);
  };
}

class Store {
  products: Product[] = [];

  @logAccess
  addProduct(product: Product): Product[] {
    this.products = [...this.products, product];
    return this.products;
  }
}

const store = new Store();
const laptop: Product = { id: "P001", name: "Laptop", price: 999 };
store.addProduct(laptop);
// Çıxış: Accessing addProduct with args: [{"id":"P001","name":"Laptop","price":999}]
console.log(store.products); // Çıxış: [{ id: "P001", name: "Laptop", price: 999 }]

